SELECT * FROM nx_machine_paper_refill_record


        AND nx_prr_device_id = #{deviceId}


        AND nx_prr_operator_id = #{operatorId}


        AND nx_prr_refill_type = #{refillType}


        AND DATE(nx_prr_create_time) >= #{startDate}


        AND DATE(nx_prr_create_time) <= #{stopDate}


ORDER BY nx_prr_create_time DESC

    LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM nx_machine_paper_refill_record


        AND nx_prr_device_id = #{deviceId}


        AND nx_prr_operator_id = #{operatorId}

SELECT * FROM nx_machine_paper_refill_record
WHERE nx_prr_device_id = #{deviceId}
ORDER BY nx_prr_create_time DESC

    LIMIT #{offset}, #{limit}

SELECT * FROM nx_machine_paper_refill_record
WHERE nx_prr_operator_id = #{operatorId}
ORDER BY nx_prr_create_time DESC

    LIMIT #{offset}, #{limit}

SELECT prr.nx_prr_id AS recordId, prr.nx_prr_device_id AS deviceId, pd.nx_pd_device_name AS deviceName, pd.nx_pd_device_no AS deviceNo, prr.nx_prr_refill_type AS refillType, CASE prr.nx_prr_refill_type WHEN 1 THEN '正常换纸' WHEN 3 THEN '手动校准' ELSE '未知' END AS refillTypeName, prr.nx_prr_paper_type AS paperType, CASE prr.nx_prr_paper_type WHEN 1 THEN '整张' WHEN 2 THEN '半张' WHEN 3 THEN '三分之一张' ELSE '未知' END AS paperTypeName, prr.nx_prr_add_count AS addCount, prr.nx_prr_waste_count AS wasteCount, prr.nx_prr_after_count AS paperCount, prr.nx_prr_remark AS remark, prr.nx_prr_operator_id AS operatorId, COALESCE(mm.nx_mm_name, '系统') AS operatorName, COALESCE(mm.nx_mm_phone, '') AS operatorPhone, prr.nx_prr_create_time AS createTime FROM nx_machine_paper_refill_record prr INNER JOIN nx_machine_printer_device pd ON prr.nx_prr_device_id = pd.nx_pd_id LEFT JOIN nx_machine_market_manager mm ON prr.nx_prr_operator_id = mm.nx_mm_id WHERE pd.nx_pd_market_id = #{marketId}
AND DATE(prr.nx_prr_create_time) >= #{startDate}
AND DATE(prr.nx_prr_create_time) <= #{stopDate}
ORDER BY prr.nx_prr_create_time DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM nx_machine_paper_refill_record prr
INNER JOIN nx_machine_printer_device pd ON prr.nx_prr_device_id = pd.nx_pd_id
WHERE pd.nx_pd_market_id = #{marketId}

    AND DATE(prr.nx_prr_create_time) >= #{startDate}


    AND DATE(prr.nx_prr_create_time) <= #{stopDate}

SELECT pd.nx_pd_id AS deviceId, pd.nx_pd_device_name AS deviceName, pd.nx_pd_device_no AS deviceNo, pd.nx_pd_paper_count AS currentPaperCount, pd.nx_pd_paper_type AS paperType, CASE pd.nx_pd_paper_type WHEN 1 THEN '整张' WHEN 2 THEN '半张' WHEN 3 THEN '三分之一张' ELSE '未知' END AS paperTypeName, COUNT(prr.nx_prr_id) AS refillCount, COALESCE(SUM(CASE WHEN prr.nx_prr_refill_type = 1 THEN prr.nx_prr_add_count ELSE 0 END), 0) AS totalRefill, COALESCE(SUM(CASE WHEN prr.nx_prr_refill_type = 1 THEN prr.nx_prr_waste_count ELSE 0 END), 0) AS refillWaste, COALESCE(SUM(CASE WHEN prr.nx_prr_refill_type = 3 THEN prr.nx_prr_waste_count ELSE 0 END), 0) AS calibrateWaste, COALESCE(SUM(prr.nx_prr_waste_count), 0) AS totalWaste, MAX(prr.nx_prr_create_time) AS lastRefillTime FROM nx_machine_printer_device pd INNER JOIN nx_machine_paper_refill_record prr ON pd.nx_pd_id = prr.nx_prr_device_id WHERE pd.nx_pd_market_id = #{marketId}
AND DATE(prr.nx_prr_create_time) >= #{startDate}
AND DATE(prr.nx_prr_create_time) <= #{stopDate}
GROUP BY pd.nx_pd_id, pd.nx_pd_device_name, pd.nx_pd_device_no, pd.nx_pd_paper_count, pd.nx_pd_paper_type ORDER BY lastRefillTime DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(DISTINCT pd.nx_pd_id)
FROM nx_machine_printer_device pd
INNER JOIN nx_machine_paper_refill_record prr ON pd.nx_pd_id = prr.nx_prr_device_id
WHERE pd.nx_pd_market_id = #{marketId}

    AND DATE(prr.nx_prr_create_time) >= #{startDate}


    AND DATE(prr.nx_prr_create_time) <= #{stopDate}

SELECT prr.nx_prr_id AS recordId, prr.nx_prr_device_id AS deviceId, pd.nx_pd_device_name AS deviceName, pd.nx_pd_device_no AS deviceNo, prr.nx_prr_refill_type AS refillType, CASE prr.nx_prr_refill_type WHEN 1 THEN '正常换纸' WHEN 3 THEN '手动校准' ELSE '未知' END AS refillTypeName, prr.nx_prr_paper_type AS paperType, CASE prr.nx_prr_paper_type WHEN 1 THEN '整张' WHEN 2 THEN '半张' WHEN 3 THEN '三分之一张' ELSE '未知' END AS paperTypeName, prr.nx_prr_add_count AS addCount, prr.nx_prr_waste_count AS wasteCount, prr.nx_prr_after_count AS paperCount, prr.nx_prr_remark AS remark, prr.nx_prr_operator_id AS operatorId, COALESCE(mm.nx_mm_name, '系统') AS operatorName, COALESCE(mm.nx_mm_phone, '') AS operatorPhone, prr.nx_prr_create_time AS createTime FROM nx_machine_paper_refill_record prr INNER JOIN nx_machine_printer_device pd ON prr.nx_prr_device_id = pd.nx_pd_id LEFT JOIN nx_machine_market_manager mm ON prr.nx_prr_operator_id = mm.nx_mm_id WHERE prr.nx_prr_device_id = #{deviceId}
AND DATE(prr.nx_prr_create_time) >= #{startDate}
AND DATE(prr.nx_prr_create_time) <= #{stopDate}
ORDER BY prr.nx_prr_create_time DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM nx_machine_paper_refill_record prr
WHERE prr.nx_prr_device_id = #{deviceId}

    AND DATE(prr.nx_prr_create_time) >= #{startDate}


    AND DATE(prr.nx_prr_create_time) <= #{stopDate}

SELECT COUNT(*) FROM nx_machine_paper_refill_record
WHERE nx_prr_device_id = #{deviceId}

    AND nx_prr_create_time >= #{startTime}


    AND nx_prr_create_time <= #{endTime}

SELECT SUM(nx_prr_add_count) FROM nx_machine_paper_refill_record
WHERE nx_prr_device_id = #{deviceId}
  AND nx_prr_refill_type = 1

    AND nx_prr_create_time >= #{startTime}


    AND nx_prr_create_time <= #{endTime}
